// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check content popup', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check content popup', async function() {
    await driver.get("http://localhost:4200/admin-user/list-department");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-layout-content")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.css(".ant-table-row:nth-child(1) .ant-space-item:nth-child(2) svg")).click();
    await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography")).click();
    await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography")).click();
    await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography")).click();
    {
      const element = await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }
    await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography")).click();
    await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography")).click();
    {
      const element = await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }
    assert(await driver.findElement(By.css("div:nth-child(1) > div > .ant-typography")).getText() == "部署を削除します。よろしいですか。");
  });
});
